package main

import (
	"fmt"
	"log"
	"net/http"
	"strconv"

	"github.com/prometheus/client_golang/api"
	"github.com/prometheus/client_golang/model"
	"github.com/prometheus/common/logql"
)

// Registry stores the metrics
var registry = api.NewSimpleCollectorRegistry()

func main() {
	// Create a counter for per-user, per-request tracking
	userRequestsTotal := prometheus.NewCounterVec(
		prometheus.CounterOpts{
			Name: "user_requests_total",
			Help: "The total number of requests per user",
		},
		[]string{"user", "method"},
	)
	registry.MustRegister(userRequestsTotal)

	http.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
		// Increment the counter for the current user and request method
		userRequestsTotal.WithLabelValues(r.URL.Query().Get("user"), r.Method).Inc()

		fmt.Fprintf(w, "Hello, %s!", r.URL.Query().Get("user"))
	})

	log.Println("Starting server on :8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}